import styled from "styled-components"
import Brand from '../LandingPage/Brand'

const Footer = () => {
  return (
    <FooterContainer>
      <Brand />
      <div style={{ display: "flex", columnGap: "5em" }}>
        <ul>
          <li> Quick Links </li>
          <li> a </li>
          <li> b </li>
        </ul>
        <ul>
          <li> Contact </li>
          <li> a </li>
          <li> b </li>
        </ul>
      </div>
      <Copyright> © 2021 Adam Jałocha </Copyright>
    </FooterContainer>
  )
}

const FooterContainer = styled.footer`
  color: white;

  display: grid;
  grid-template-columns: auto auto auto;
  grid-template-rows: 1fr auto;
  row-gap: 2em;
  padding-top: 2em;
  width: 100%;

  align-items: center;
  justify-content: space-around;
`

const Copyright = styled.span`
  grid-row: 2;
  grid-column: 1/4;
  text-align: center;
  padding: 1em 0;
  box-shadow: 0px 0px 2px red;
`

export default Footer
